return [
  { json: { lab: 'openai', url: 'https://openai.com/news/rss.xml' } },
  { json: { lab: 'google', url: 'https://blog.google/technology/ai/rss/' } },
  { json: { lab: 'huggingface', url: 'https://huggingface.co/blog/feed.xml' } },
  { json: { lab: 'otros', url: 'http://export.arxiv.org/rss/cs.AI' } },
];

const crypto = require('crypto');
const TRENDING_KEYWORDS = ['GPT-', 'Claude ', 'Gemini ', 'Llama '];

return items.map((item) => {
  const link = item.json.link;
  const title = item.json.title ?? '';
  const snippet = (item.json.contentSnippet ?? item.json.summary ?? item.json.description ?? '').replace(/<[^>]+>/g, '');
  const pubDate = item.json.pubDate ? new Date(item.json.pubDate) : new Date();
  const dateStr = pubDate.toISOString().slice(0, 10);
  const hash = crypto.createHash('sha256').update(link).digest('hex').slice(0, 8);
  const slug = `${dateStr}-${hash}`;
  const trending = TRENDING_KEYWORDS.some((kw) => title.includes(kw));
  return {
    json: {
      lab: item.json.lab,
      slug,
      title,
      link,
      snippet,
      publishedAt: dateStr,
      trending,
    },
  };
});

return items.map((item) => {
  const MAX = 280;
  let text = item.json.snippet ?? '';
  if (text.length > MAX) {
    const cut = text.slice(0, MAX);
    const lastPeriod = cut.lastIndexOf('. ');
    text = (lastPeriod > 100 ? cut.slice(0, lastPeriod + 1) : cut) + '…';
  }
  return { json: { ...item.json, descriptionEn: text } };
});

return items.map((item) => {
  const ok = item.json.statusCode === 200 && item.json.translatedText;
  return {
    json: {
      ...item.json,
      titleEs: ok ? item.json.translatedText.split('\n\n')[0] : item.json.title,
      descriptionEs: ok ? item.json.translatedText.split('\n\n')[1] : item.json.descriptionEn,
      translationOutdated: !ok,
    },
  };
});
